/**
 * Landing — first screen before the use case library.
 * Chrome uses neutral accent-ui; no Claude orange here.
 */

import React from "react";

/**
 * @param {Object} props
 * @param {function} props.onContinue — navigate to use case library
 */
function LandingPage({ onContinue }) {
  return (
    <div className="min-h-screen bg-bg text-text-primary">
      <main className="mx-auto flex max-w-2xl flex-col items-center px-6 pb-24 pt-20 text-center sm:pt-28">
        <h1 className="text-4xl font-bold tracking-tight text-text-primary sm:text-5xl">ai-roundtable</h1>
        <p className="mt-4 text-lg text-text-secondary">Putting the best frontier minds to work.</p>
        <p className="mt-10 max-w-xl text-sm leading-relaxed text-text-secondary sm:text-base">
          A thinking session with four frontier models and a thorough intake — so you leave with
          something you can act on, not a generic answer.
        </p>
        <button
          type="button"
          onClick={onContinue}
          className="mt-14 rounded-lg border border-border bg-surface px-8 py-3 text-sm font-medium text-text-primary transition-colors hover:border-accent-ui focus:border-border-focus focus:outline-none"
        >
          Browse use cases
        </button>
      </main>
    </div>
  );
}

export default LandingPage;
